# Load dependency assemblies first \(reflection-only context\)
$nuget = "C:\\Users\\mibil\\.nuget\\packages"
$deps = @\(
    "$nuget\\sharpdx\\4.2.0\\lib\\net45\\SharpDX.dll",
    "$nuget\\sharpdx.direct3d11\\4.2.0\\lib\\net45\\SharpDX.Direct3D11.dll",
    "$nuget\\sharpdx.direct3d9\\4.2.0\\lib\\net45\\SharpDX.Direct3D9.dll",
    "$nuget\\sharpdx.dxgi\\4.2.0\\lib\\net45\\SharpDX.DXGI.dll",
    "$nuget\\sharpdx.mathematics\\4.2.0\\lib\\net45\\SharpDX.Mathematics.dll",
    "$nuget\\sharpdx.d3dcompiler\\4.2.0\\lib\\net45\\SharpDX.D3DCompiler.dll",
    "$nuget\\helixtoolkit.wpf.sharpdx\\2.25.0\\lib\\net462\\HelixToolkit.Wpf.SharpDX.dll"
\)

foreach \($dep in $deps\) {
    if \(Test-Path $dep\) {
        try {
            [System.Reflection.Assembly]::ReflectionOnlyLoadFrom\($dep\) | Out-Null
            Write-Host "Loaded: $dep"
        } catch {
            Write-Host "Skipped: $dep — $\($_.Exception.Message\)"
        }
    } else {
        Write-Host "NOT FOUND: $dep"
    }
}

$asm = [System.AppDomain]::CurrentDomain.ReflectionOnlyGetAssemblies\(\) |
    Where-Object { $_.GetName\(\).Name -eq "HelixToolkit.Wpf.SharpDX" }

if \(-not $asm\) { Write-Host "Helix assembly not loaded"; exit 1 }

try {
    $types = $asm.GetTypes\(\)
} catch [System.Reflection.ReflectionTypeLoadException] {
    $types = $_.Exception.Types | Where-Object { $_ -ne $null }
}

$type = $types | Where-Object { $_.Name -eq "CameraController" }
if \($type\) {
    Write-Host "`nFound: $\($type.FullName\)`n"
    $type.GetProperties\(\) |
        Where-Object { $_.Name -match "Pan|Mouse|Gesture|Button|Bind|Rotate|Zoom" } |
        ForEach-Object { "{0,-55} {1}" -f $_.Name, $_.PropertyType.Name }
} else {
    Write-Host "CameraController not found. Camera-related types:"
    $types | Where-Object { $_.Name -match "Camera" } | Select-Object -ExpandProperty FullName
}
